// utils/cacheUtils.js
let cache = {};

// Función para limpiar imágenes SOLO para guardar en cache
const cleanDataForCache = (data) => {
  if (Array.isArray(data)) {
    return data.map(item => cleanDataForCache(item));
  }
  
  if (data && typeof data === 'object') {
    const cleaned = { ...data };
    // Eliminar propiedades que contienen imágenes SOLO DEL CACHE
    delete cleaned.imagen;
    delete cleaned.logo;
    delete cleaned.image;
    delete cleaned.thumbnail;
    delete cleaned.foto;
    delete cleaned.photo;
    
    // Limpiar nested objects si es necesario
    Object.keys(cleaned).forEach(key => {
      if (cleaned[key] && typeof cleaned[key] === 'object') {
        cleaned[key] = cleanDataForCache(cleaned[key]);
      }
    });
    
    return cleaned;
  }
  
  return data;
};

export const cacheManager = {
  set: (key, data) => {
    // Limpiar imágenes antes de guardar en cache
    const cleanedData = cleanDataForCache(data);
    cache[key] = {
      data: cleanedData,
      timestamp: Date.now(),
      // Guardamos también las URLs de imágenes por separado
      imageUrls: extractImageUrls(data)
    };
  },
  
  get: (key) => {
    const item = cache[key];
    if (!item) return null;
    
    // Devolver los datos sin imágenes
    return item.data;
  },
  
  // Nuevo método para obtener URLs de imágenes del cache
  getImageUrls: (key) => {
    const item = cache[key];
    return item ? item.imageUrls : null;
  },
  
  remove: (key) => {
    delete cache[key];
  },
  
  clear: () => {
    cache = {};
  }
};

// Función para extraer solo las URLs de imágenes
const extractImageUrls = (data) => {
  if (Array.isArray(data)) {
    return data.map(item => extractImageUrls(item));
  }
  
  if (data && typeof data === 'object') {
    const imageUrls = {};
    
    // Extraer URLs de imágenes
    if (data.imagen) imageUrls.imagen = data.imagen;
    if (data.logo) imageUrls.logo = data.logo;
    if (data.image) imageUrls.image = data.image;
    if (data.thumbnail) imageUrls.thumbnail = data.thumbnail;
    if (data.foto) imageUrls.foto = data.foto;
    if (data.photo) imageUrls.photo = data.photo;
    
    return imageUrls;
  }
  
  return {};
};
